const { Manifold, label } = api;

// Axis-aligned box from min..max corner.
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// 16mm cube head, front face at y = +8.
const head = Manifold.cube([16, 16, 16], true);

// Face features are thin raised relief on the FRONT face. The app's
// default camera looks at the -Y / -X corner, so -Y is "front": features
// sit at y -8.5..-7.5, overlapping the head body by 0.5 for a clean union.
const fy = [-8.5, -7.5];

function plate(x0, x1, z0, z1) { return box([x0, fy[0], z0], [x1, fy[1], z1]); }

// Eyes: two 4x4 squares.
const eyes = plate(-6, -2, 2, 6).add(plate(2, 6, 2, 6));

// Classic creeper frown.
const mouth = plate(-2, 2, 0, 2) // top center
  .add(plate(-4, 4, -4, 0)) // wide middle
  .add(plate(-4, -2, -6, -4)) // left foot
  .add(plate(2, 4, -6, -4)); // right foot

return label(head, 'head')
  .add(label(eyes, 'eyes'))
  .add(label(mouth, 'mouth'));
